SELECT menu_id, menu_name, menu_type, description, parent_id, menu_path, menu_order, reg_id, reg_dt, chg_id, chg_dt, del_id, del_dt, del_yn FROM menu
AND menu_id IN
#{menuId}
AND menu_name ILIKE '%' || #{filter.menuName} || '%'
AND menu_type = #{filter.menuType}
AND menu_path ILIKE '%' || #{filter.menuPath} || '%'
AND parent_id = #{filter.parentId}
AND del_yn = #{filter.delYn}

