mapper.select:
WITH RECURSIVE menu_tree AS ( -- Base case: 선택된 헤더 메뉴의 직계 자식들 SELECT m.menu_id, m.menu_name, m.menu_type, m.description, m.parent_id, m.menu_path, m.menu_order, m.reg_id, m.reg_dt, m.chg_id, m.chg_dt, m.del_id, m.del_dt, m.del_yn FROM menu m
m.parent_id IN
#{headerId}
UNION ALL
-- Recursive case: 자식의 자식들 SELECT m.menu_id, m.menu_name, m.menu_type, m.description, m.parent_id, m.menu_path, m.menu_order, m.reg_id, m.reg_dt, m.chg_id, m.chg_dt, m.del_id, m.del_dt, m.del_yn FROM menu m INNER JOIN menu_tree mt ON m.parent_id = mt.menu_id
) SELECT * FROM menu_tree ORDER BY menu_order, menu_name
